class Scanner:

    def __init__(self, target_dir):
        self.target_dir = Path(target_dir).resolve()
        self.graph = nx.DiGraph()
        self.parsers = {'.py': PythonParser()}
        self.ignore_dirs = {'.git', '__pycache__', 'venv', 'bin', 'lib', 'lib64', 'include'}

    def scan(self):
        """Recursively scan and build a networkx DiGraph of the project structure."""
        root_name = self.target_dir.name or str(self.target_dir)
        self.graph.add_node('.', type='directory', name=root_name, path='.')
        for root, dirs, files in os.walk(self.target_dir):
            dirs[:] = [d for d in dirs if d not in self.ignore_dirs]
            rel_root = Path(root).relative_to(self.target_dir)
            parent_node = str(rel_root)
            for d in dirs:
                dir_path = str(rel_root / d)
                self.graph.add_node(dir_path, type='directory', name=d, path=dir_path)
                self.graph.add_edge(parent_node, dir_path)
            for f in files:
                file_path = Path(root) / f
                rel_file_path = str(rel_root / f)
                extension = file_path.suffix.lower()
                line_count = 0
                content = ''
                try:
                    with open(file_path, 'r', encoding='utf-8', errors='ignore') as file_obj:
                        content = file_obj.read()
                        line_count = len(content.splitlines())
                except Exception:
                    pass
                self.graph.add_node(rel_file_path, type='file', name=f, path=rel_file_path, extension=extension, line_count=line_count, file_type=self._guess_type(extension), source=content)
                self.graph.add_edge(parent_node, rel_file_path)
                if extension in self.parsers:
                    components, imports = self.parsers[extension].parse(content)
                    self._add_components(rel_file_path, components)
                    self.graph.nodes[rel_file_path]['imports'] = imports
        return (self.graph, '.')

    def _add_components(self, parent_node, components, prefix=''):
        """Recursively add components to the graph."""
        for comp in components:
            node_name = comp.get('short_name', comp['name'])
            comp_id = f'{parent_node}::{prefix}{node_name}'
            children = comp.pop('children', [])
            self.graph.add_node(comp_id, **comp)
            self.graph.add_edge(parent_node, comp_id)
            if children:
                self._add_components(comp_id, children, prefix=f'{node_name}.')

    def _guess_type(self, extension):
        code_exts = {'.py', '.js', '.ts', '.c', '.cpp', '.go', '.rs', '.java', '.sh', '.bash'}
        config_exts = {'.json', '.yaml', '.yml', '.toml', '.xml', '.ini', '.env'}
        doc_exts = {'.md', '.txt', '.pdf', '.html', '.css'}
        if extension in code_exts:
            return 'code'
        if extension in config_exts:
            return 'config'
        if extension in doc_exts:
            return 'doc'
        return 'other'

def __init__(self, target_dir):
    self.target_dir = Path(target_dir).resolve()
    self.graph = nx.DiGraph()
    self.parsers = {'.py': PythonParser()}
    self.ignore_dirs = {'.git', '__pycache__', 'venv', 'bin', 'lib', 'lib64', 'include'}

def _add_components(self, parent_node, components, prefix=''):
    for comp in components:
        node_name = comp.get('short_name', comp['name'])
        comp_id = f'{parent_node}::{prefix}{node_name}'
        children = comp.pop('children', [])
        self.graph.add_node(comp_id, **comp)
        self.graph.add_edge(parent_node, comp_id)
        if children:
            self._add_components(comp_id, children, prefix=f'{node_name}.')

def _guess_type(self, extension):
    code_exts = {'.py', '.js', '.ts', '.c', '.cpp', '.go', '.rs', '.java', '.sh', '.bash'}
    config_exts = {'.json', '.yaml', '.yml', '.toml', '.xml', '.ini', '.env'}
    doc_exts = {'.md', '.txt', '.pdf', '.html', '.css'}
    if extension in code_exts:
        return 'code'
    if extension in config_exts:
        return 'config'
    if extension in doc_exts:
        return 'doc'
    return 'other'

def _graph_to_tree(self, graph, node_id, depth=0):
    node_data = dict(graph.nodes[node_id])
    children = list(graph.successors(node_id))
    children.sort(key=lambda x: (graph.nodes[x].get('type') != 'directory', graph.nodes[x].get('type') != 'file', graph.nodes[x].get('name')))
    tree_node = {**node_data, 'depth': depth, 'children': [self._graph_to_tree(graph, child, depth + 1) for child in children]}
    return tree_node

def _get_stats(self, graph):
    total_lines = sum((data.get('line_count', 0) for _, data in graph.nodes(data=True)))
    code_count = sum((1 for _, data in graph.nodes(data=True) if data.get('file_type') == 'code'))
    total_files = sum((1 for _, data in graph.nodes(data=True) if data.get('type') == 'file'))
    return (total_lines, code_count, total_files)

def _get_functional_view(self, graph):
    functional = {'classes': [], 'functions': []}
    for node_id, data in graph.nodes(data=True):
        if data.get('type') == 'class':
            node_copy = dict(data)
            node_copy['file_path'] = node_id.split('::')[0]
            functional['classes'].append(node_copy)
        elif data.get('type') == 'function':
            node_copy = dict(data)
            parts = node_id.split('::')
            node_copy['file_path'] = parts[0]
            if len(parts) > 2:
                node_copy['parent_component'] = parts[1]
            functional['functions'].append(node_copy)
    functional['classes'].sort(key=lambda x: x['name'])
    functional['functions'].sort(key=lambda x: x['name'])
    return functional

class PythonParser(Parser):

    def parse(self, content):
        try:
            tree = ast.parse(content)
            components = self._parse_body(tree.body, include_variables=True)
            imports = self._parse_imports(tree.body)
            return (components, imports)
        except SyntaxError:
            return ([], [])

    def _parse_imports(self, body):
        """Extract imports from the AST."""
        imports = []
        for node in body:
            if isinstance(node, ast.Import):
                for alias in node.names:
                    imports.append(alias.name)
            elif isinstance(node, ast.ImportFrom):
                module = node.module if node.module else ''
                for alias in node.names:
                    imports.append(f'{module}.{alias.name}' if module else alias.name)
        return imports

    def _parse_body(self, body, include_variables=True):
        """Recursively parse a list of AST nodes."""
        components = []
        for node in body:
            if isinstance(node, ast.ClassDef):
                components.append({'name': node.name, 'type': 'class', 'short_name': node.name, 'docstring': ast.get_docstring(node), 'source': self._get_scrubbed_source(node), 'children': self._parse_body(node.body, include_variables=True)})
            elif isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                components.append(self._parse_function(node))
            elif isinstance(node, ast.Assign) and include_variables:
                for target in node.targets:
                    if isinstance(target, ast.Name):
                        components.append({'name': target.id, 'type': 'variable', 'docstring': None, 'source': ast.unparse(node)})
        return components

    def _get_scrubbed_source(self, node):
        """Returns the source code of a node with docstrings and comments removed."""
        node_copy = copy.deepcopy(node)
        if hasattr(node_copy, 'body') and node_copy.body:
            first = node_copy.body[0]
            if isinstance(first, ast.Expr) and isinstance(first.value, ast.Constant) and isinstance(first.value.value, str):
                if ast.get_docstring(node):
                    node_copy.body.pop(0)
                    if not node_copy.body:
                        node_copy.body.append(ast.Pass())
        return ast.unparse(node_copy)

    def _parse_function(self, node):
        """Helper to parse function arguments, returns, docstrings and nested children."""
        parsed_args = []
        for arg in node.args.args:
            arg_info = {'name': arg.arg, 'explicit': False, 'type': ''}
            if arg.annotation:
                try:
                    arg_info['type'] = ast.unparse(arg.annotation)
                    arg_info['explicit'] = True
                except Exception:
                    pass
            parsed_args.append(arg_info)
        return_info = {'type': 'None', 'explicit': False}
        if node.returns:
            try:
                return_info['type'] = ast.unparse(node.returns)
                return_info['explicit'] = True
            except Exception:
                pass
        else:
            return_values = []
            for child in ast.walk(node):
                if isinstance(child, ast.Return) and child.value:
                    try:
                        val = ast.unparse(child.value)
                        if val not in return_values:
                            return_values.append(val)
                    except Exception:
                        pass
            if return_values:
                return_info['type'] = ' | '.join(return_values[:3])
                return_info['explicit'] = False
        return {'name': node.name, 'type': 'function', 'short_name': node.name, 'args': parsed_args, 'returns': return_info, 'docstring': ast.get_docstring(node), 'source': self._get_scrubbed_source(node), 'children': self._parse_body(node.body, include_variables=False)}

def parse(self, content):
    try:
        tree = ast.parse(content)
        components = self._parse_body(tree.body, include_variables=True)
        imports = self._parse_imports(tree.body)
        return (components, imports)
    except SyntaxError:
        return ([], [])

def _parse_imports(self, body):
    imports = []
    for node in body:
        if isinstance(node, ast.Import):
            for alias in node.names:
                imports.append(alias.name)
        elif isinstance(node, ast.ImportFrom):
            module = node.module if node.module else ''
            for alias in node.names:
                imports.append(f'{module}.{alias.name}' if module else alias.name)
    return imports

def _parse_body(self, body, include_variables=True):
    components = []
    for node in body:
        if isinstance(node, ast.ClassDef):
            components.append({'name': node.name, 'type': 'class', 'short_name': node.name, 'docstring': ast.get_docstring(node), 'source': self._get_scrubbed_source(node), 'children': self._parse_body(node.body, include_variables=True)})
        elif isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            components.append(self._parse_function(node))
        elif isinstance(node, ast.Assign) and include_variables:
            for target in node.targets:
                if isinstance(target, ast.Name):
                    components.append({'name': target.id, 'type': 'variable', 'docstring': None, 'source': ast.unparse(node)})
    return components

def _get_scrubbed_source(self, node):
    node_copy = copy.deepcopy(node)
    if hasattr(node_copy, 'body') and node_copy.body:
        first = node_copy.body[0]
        if isinstance(first, ast.Expr) and isinstance(first.value, ast.Constant) and isinstance(first.value.value, str):
            if ast.get_docstring(node):
                node_copy.body.pop(0)
                if not node_copy.body:
                    node_copy.body.append(ast.Pass())
    return ast.unparse(node_copy)

def _parse_function(self, node):
    parsed_args = []
    for arg in node.args.args:
        arg_info = {'name': arg.arg, 'explicit': False, 'type': ''}
        if arg.annotation:
            try:
                arg_info['type'] = ast.unparse(arg.annotation)
                arg_info['explicit'] = True
            except Exception:
                pass
        parsed_args.append(arg_info)
    return_info = {'type': 'None', 'explicit': False}
    if node.returns:
        try:
            return_info['type'] = ast.unparse(node.returns)
            return_info['explicit'] = True
        except Exception:
            pass
    else:
        return_values = []
        for child in ast.walk(node):
            if isinstance(child, ast.Return) and child.value:
                try:
                    val = ast.unparse(child.value)
                    if val not in return_values:
                        return_values.append(val)
                except Exception:
                    pass
        if return_values:
            return_info['type'] = ' | '.join(return_values[:3])
            return_info['explicit'] = False
    return {'name': node.name, 'type': 'function', 'short_name': node.name, 'args': parsed_args, 'returns': return_info, 'docstring': ast.get_docstring(node), 'source': self._get_scrubbed_source(node), 'children': self._parse_body(node.body, include_variables=False)}

class Parser:

    def parse(self, content):
        raise NotImplementedError('Subclasses must implement parse()')
